import React from "react";
import styled from "styled-components";

function Jumbotron({ children, direction = "row", ...restProps }) {
  return (
    <Item {...restProps}>
      <Inner direction={direction}>
        <Pane></Pane>
      </Inner>
    </Item>
  );
}

export default Jumbotron;
